//-------------------------------------------------------------------------
// 잡손취소 함수 호출
//-------------------------------------------------------------------------
scwin.f_Cancel = async function(e) {
    try{
        if(ds_acctRecvList.getModifiedIndex().length==0){
            $c.gus.cfAlertMsg("선택하신 사항이 없습니다.");
            return false;
        }

        let ret = await $c.gus.cfValidate([ed_cancelDt]);
        if (!ret) {
            return false;
        }
        let count = 1;
        for (i=0; i< ds_acctRecvList.getRowCount(); i++){
            count = count + i;
            if (ds_acctRecvList.getCellData(i, "num") == "T") {
                if (ds_acctRecvList.getCellData(i,"cnclSlipNo") != "") {
                    $c.gus.cfAlertMsg(count+"행의 수금사항은 잡손익취소 하실수 없는 상태 입니다.");
                    ds_acctRecvList.setRowPosition(i);
                    return false;
                }
                if (ds_acctRecvList.getCellData(i,"delYn") == "1") {
                    $c.gus.cfAlertMsg(count+"행의 수금사항은 이미 삭제처리되었습니다. 확인하시기 바랍니다.");
                    ds_acctRecvList.setRowPosition(i);
                    return false;
                }
            }
        }

        if(await $c.win.confirm("선택하신 사항을 잡손익취소 하시겠습니까")) {
            for (i=0; i< ds_acctRecvList.getRowCount(); i++){
                if (ds_acctRecvList.getCellData(i, "num") == "T") {
                    // 취소일자를 각 Row에 입력한다.
				    ds_acctRecvList.setColumnDefaultValue(i,"cnclDt",ed_cancelDt.getValue());
                }
            }
            //잡손처리 Data Bind
            ds_addAcctRecvEtcLoss.insertRow(0);
            ds_addAcctRecvEtcLoss.setCellData(0, "queryDeptSearchStDate", ed_FromDate.getValue());//시작일자(부서검색시 이용되는 조건)
            ds_addAcctRecvEtcLoss.setCellData(0, "queryDeptSearchEndDate", ed_ToDate.getValue());//종료일자(부서검색시 이용되는 조건)

            sbm_saveAcctRecvEtcLoss.action ="/ac.fm.acctrecvmgnt.acctrecvcontmgnt.CancelAccountReceivableEtclossCMD.do";
            $c.sbm.execute(sbm_saveAcctRecvEtcLoss);
        }
    } catch (e) {
       console.log("f_Cancel : " + e);
    }
};

//-------------------------------------------------------------------------
// 잡손취소 콜백
//-------------------------------------------------------------------------
scwin.sbm_saveAcctRecvEtcLoss_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0){
            for (i=0; i< ds_acctRecvList.getRowCount(); i++){
                ds_acctRecvList.undoRow(i);//ds_acctRecvList.UndoAll();
            }
            return; //onFail
        }
        $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();

        if ($p.parent().tabControl1.getWindow(0).ed_sclntNo.getValue() != "" && $p.parent().tabControl1.getWindow(0).ed_sacctDeptCd.getValue()!= "" ) {
            $p.parent().tabControl1.getWindow(0).scwin.f_Retrieve();
        }
    } catch (e) {
       console.log("sbm_saveAcctRecvEtcLoss_submitdone : " + e);
    }
};
